	//functions to extract degrees minutes seconds
	 function dd(deg){
		var degs;
		if(deg > 0){
			if(deg<10){
				degs = "+0"+Math.floor(deg);
			}else{
				degs = "+"+Math.floor(deg);
			}
        }else{
		 //if( deg > -1){
