        deg = Math.abs(deg);
        mini = ((deg - Math.floor(deg)) * 60);
		degs= Math.round((mini - Math.floor(mini)) * 60);
		if(degs<10){
			degs="0"+degs;
		}
		return degs;
		
    }

	//zero pad string
	function str_pad(n) {
		return String("00" + n).slice(-2);
	}

	function rad2deg (angle) {
	  return angle * 57.29577951308232 
	}

	function deg2rad (angle) {
	  return angle * 0.017453292519943295
	}
	
	//get ra dec from simbad
	function simbad(num){
	save_plan=false;
		//$("#TargetStatus_"+num).html("Searching &nbsp;<img src=\"images/ajax-loader.gif\">");
		json={};
		var outgoing = {};
			outgoing['target']=$("#simbad").val();
			outgoing['details']="full";
		var jsonString = encodeURIComponent(JSON.stringify(outgoing));
		//var jsonString2=jsonString;
		$.ajax({ type: "POST",
			url: "ajax/simbadlookup.php",
			async: true,
			timeout: 5000,
			data: 'json=' +jsonString,
			dataType: "json",
			success: function (data) {
				if (data.success == true){		

					
					targetRA = data.ra;
					targetDEC = data.dec;
									
					if($("#decDegs").prop("checked") == true){

						$("#ra").val(targetRA.toFixed(5));
						$("#dec").val((targetDEC).toFixed(5));

					}else{

						$("#ra").val(hh(targetRA/15)+"h "+dm(targetRA/15)+"m "+ds(targetRA/15)+"s");
						$("#dec").val(dd(targetDEC)+ String.fromCharCode(176) +" "+dm(targetDEC)+"' "+ds(targetDEC)+"\"");
						
					}
					
					update();
					
					var types = data.type.split(',');
					$("#objdetails").html("<b>Type:</b> "+types[0]+"<br>");
					$("#objdetails").append("<b>Proper motions </b>mas/yr :  "+data.pmra+"  "+data.pmdec+" <br>");
					
					if(data.Bmag!=99){
						$("#objdetails").append("<b>B mag: </b>"+data.Bmag+"<br>");
					}
					if(data.Vmag!=99){
						$("#objdetails").append("<b>V mag: </b>"+data.Vmag+"<br>");
					}
					if(data.Rmag!=99){
						$("#objdetails").append("<b>R mag:</b> "+data.Rmag+"<br>");
					}
					if(data.Imag!=99){
						$("#objdetails").append("<b>I mag:</b> "+data.Imag+"<br>");
					}
				
					$("#status").html(" Coordinates found <font color=\"#00FF00\">&#x2714;</font>");
								
				}else{
					if(data.reason=='3'){
						$("#status").html(" Name not found in Simbad \""+data.name.replace(/<[^>]*>?/gm, '')+"\"<font color=\"#FF0000\">&#x2718;</font>");
					}else if(data.reason=='4'){
						$("#status").html(" Coordinates not found <font color=\"#FF0000\">&#x2718;</font>");
					}else if(data.reason=='2'){
						$("#status").html(" Curl error: - "+data.details +"<font color=\"#FF0000\">&#x2718;</font>");
					}else{
						$("#status").html(" Error: "+data.reason+" - "+data.details +"<font color=\"#FF0000\">&#x2718;</font>");
					}
				}
			}, 
			error: function(jqXHR, textStatus, errorThrown) {
				if(textStatus=="error"){
					$("#status").html(" Server lost </b><font color=\"#FF0000\">&#x2718;</font> Try reloading the page");
				}else if(textStatus=="parsererror"){
					$("#status").html(" Server error </b><font color=\"#FF0000\">&#x2718;</font> Try reloading the page");
					//$("#TargetStatus_"+num).html(errorThrown);
				}else{
					$("#status").html(textStatus);
				}
			}
		});
	}
	
