		var dec = $("#dec").val().replace('−', '-').replace(/[^\d\+\-\.]+/g, " ").trim().split(/[\s]+/);
		
		var radss = $("#ra").val().replace('−', '-');
		var decdss = $("#dec").val().replace('−', '-');

		console.log(ra);
		console.log(dec);
		
		var raD;
		var decD;
		
		if($("#decDegs").prop("checked") == true){
			raD = parseFloat(ra[0]);
			decD = parseFloat(dec[0]);
			
		}else{
	
				
			//parse coordinates
			if(ra.length==3){
				raD = (parseFloat(ra[0])+(parseFloat(ra[1])/60)+(parseFloat(ra[2])/3600))*15;			
			}else if(ra.length==2){
				raD = (parseFloat(ra[0])+(parseFloat(ra[1])/60))*15;			
			}else{
				raD = parseFloat(ra[0])*15;
			}
			
			if(dec.length==3){
				decD = (Math.abs(parseFloat(dec[0]))+(parseFloat(dec[1])/60)+(parseFloat(dec[2])/3600));			
			}else if(dec.length==2){
				decD = (Math.abs(parseFloat(dec[0]))+(parseFloat(dec[1])/60));			
			}else{
				decD = Math.abs(parseFloat(dec[0]));
			}
			
			if(dec[0].indexOf("-")==0){
				decD=0-decD;			
			}
		}
		
		
		if($('#showfinderchart').prop('checked')) {
			console.log("finder chart");
			//dss pic
			var url = "//archive.stsci.edu/cgi-bin/dss_search?ra="+radss+"&dec="+decdss+"&%20equinox=J2000&height="+fovh[scope]+"&generation=3&width="+fovw[scope]+"&format=GIF";
		
			$("#chart").attr("src", url);
