			$("#xhair1").hide();
			$("#xhair2").hide();
		}
		
		if($('#showgraph').prop('checked')) {
			$("#graphcontainer").show();
		}else{
			$("#graphcontainer").hide();
		}
		

		
		
		
		console.log(raD+ " "+decD);
		
		var ra = deg2rad(raD);
		var dec = deg2rad(decD);
		
	
		
																//month is zero indexed, because javaScript
		var date = new Date(Date.UTC($("#year").val(), ($("#month").val()-1), $("#day").val(), 12,0,0,0));
		var unixtime = date.getTime()/1000
		
		console.log(date);
		
		console.log(unixtime);
		
		var JDE=(unixtime/86400.0)+ 2440587.5;
		var T = (JDE - 2451545.0)/36525;
		
		console.log(JDE);
		
		var unix;
		var d;
		var sunPos;
		var sunalt;
		var theta;
		var H;
		var alt;
		var az;
		
		var sunset=0;
		var sunrise=0;
		
		var lat=51.774883;
		var lon=0.094405;
		var latrad = deg2rad(lat);
		
		var az_r;
		var scopealt;
		
		var rise1=0;
		var set1=0;
		var rise2=0;
		var set2=0;
		
		var a_rise1=0;
		var a_set1=0;
		var a_rise2=0;
		var a_set2=0;
		
		var observable=0;
		
		var moonDist=0;
		
		data[0].data=[];
		data[1].data=[];
		data[2].data=[];
		data[3].data=[];
		data[4].data=[];
		
		posTarget = [];
		posScope = [];
		posMoon = [];
		altMoon = [];
		phaseMoon = [];
		
		var meanMoonPhase = 0;
		var minMoonDist = 180;
		var maxAlt = 0;
		
		var maxAltTime;
		
		//loop every minute of the day
		for(i = 0; i<1440; i++){
			
			unix = unixtime+(i*60);
			d = new Date(unix*1000);
			//console.log(unix);
			//console.log(i);
			//console.log(d);
			
			//sun altitude
			sunPos = SunCalc.getPosition(d,  lat, lon);
			moonPos = SunCalc.getMoonPosition(d,  lat, lon);
			MoonPhase = SunCalc.getMoonIllumination(d);
			
			sunalt = rad2deg(sunPos.altitude);
		
			
			if(sunset==0 && sunalt<-12){
				sunset=d;			
			}
			
			if(sunset!=0 && sunrise==0 && sunalt>-12){
				sunrise=d;			
			}
			
			
			JDE=(unix/86400.0)+ 2440587.5;
			T = (JDE - 2451545.0)/36525;
			theta=280.46061837 + (360.98564736629 *  (JDE-2451545)) + (0.000387933 * T * T) - ((T*T*T)/38710000);
			H=deg2rad(theta-lon)-ra;
			
			//alt az of target
			alt =rad2deg(Math.asin(((Math.sin(latrad))*(Math.sin(dec)))+((Math.cos(latrad))*(Math.cos(dec))*(Math.cos(H)))));
			
			moonDist = rad2deg(Math.acos(Math.sin(moonPos.dec)*Math.sin(dec)+Math.cos(moonPos.dec)*Math.cos(dec)*Math.cos(moonPos.ra-ra)));
			//console.log(rad2deg(moonPos.dec)+" "+moonDist);
			
			//alt = (alt + 360) % 360; 
			az =rad2deg(Math.atan2(Math.sin(H),(Math.cos(H)*Math.sin(latrad))-(Math.tan(dec)*Math.cos(latrad))))+180;
			az = (az + 360) % 360; 
			az_r=Math.round(az*2);
			if(az_r==720){az_r=0;}
			
			scopealt=horizons[scope][az_r];
			
			if(sunalt<-12){
				posTarget[i] = [unix*1000,alt];				
				posScope[i] = [unix*1000,scopealt];
				//posMoon[i] = [unix*1000,rad2deg(moonPos.altitude)];
				posMoon[i] = [unix*1000,moonDist];
				altMoon[i] = [unix*1000,rad2deg(moonPos.altitude)];
				phaseMoon[i] = [unix*1000,MoonPhase.fraction*100];
				//console.log(moonDist);
				if(moonDist<minMoonDist){minMoonDist=moonDist;}
				if(alt>maxAlt){maxAlt=alt; maxAltTime = d }
			}
			
			if(i==720){
				meanMoonPhase = MoonPhase.fraction*100;
			}
			
			//console.log(d +" "+az_r + " "+alt +" "+scopealt+" "+sunalt);
			
			
			if(alt>scopealt && sunalt<-12){
				observable++;
				//visible
				if(rise1==0){
					//just become visible
					console.log("rise1 "+d +" "+az +  " "+az_r+" "+ alt + " "+scopealt + " "+ sunalt);
					rise1=d;
					a_rise1=alt;
				}else if(rise1!=0 && set1!=0 && rise2==0){
					//become visible for 2nd time
					rise2=d;
					a_rise2=alt;
					console.log("rise2 "+d +" "+az + " "+az_r+" "+ alt + " "+scopealt + " "+ sunalt);
				}
				
				
			}else{
				//not visible
				if(set1==0 && rise1!=0){
					//set for 1st time
					set1=d;
					a_set1=alt;;
					console.log("set1 "+d +" "+az +  " "+az_r+" "+ alt + " "+scopealt + " "+ sunalt);
				}else if(set1!=0 && rise2!=0 && set2==0){
					//set for 2nd time
					set2=d;
					a_set2=alt;
					console.log("set2 "+d +" "+az +  " "+az_r+" "+ alt + " "+scopealt + " "+ sunalt);
				}
				
			}
			
			
			
		}
		observable=observable/60; //hours
		
		console.log("times "+rise1 + " "+ set1 + " "+rise2 + " "+ set2+ " "+observable);
		console.log("alts "+a_rise1 + " "+ a_set1 + " "+a_rise2 + " "+ a_set2);
		console.log("mean moon phase: "+meanMoonPhase);
		console.log("max alt: "+maxAlt);
		console.log("min moon dist: "+minMoonDist);
		//console.log(sunrise);
		//console.log(sunalt);
		
		
		data[0].data=posTarget;
		data[1].data=posScope;
		data[2].data=posMoon;
		data[3].data=altMoon;
		data[4].data=phaseMoon;
		
		console.log(data);
		$.plot( $("#placeholder"), data, options);
		
		if(rise1!=0){
		//obs1
			$("#target").html("Target visible from <b>"+str_pad(rise1.getUTCHours())+":"+str_pad(rise1.getUTCMinutes()) + "</b> ("+a_rise1.toFixed(1)+"&deg;) to <b>"+str_pad(set1.getUTCHours())+":"+str_pad(set1.getUTCMinutes()) + " </b>("+a_set1.toFixed(1)+"&deg;)");
		
		}else{
			$("#target").html("Target not visible this night");			
		}
		
		if(rise2!=0){
			$("#target").append(" and from <b>"+str_pad(rise2.getUTCHours())+":"+str_pad(rise2.getUTCMinutes()) + "</b> ("+a_rise2.toFixed(1)+"&deg;) to <b>"+str_pad(set2.getUTCHours())+":"+set2.getUTCMinutes() + "</b> ("+a_set2.toFixed(1)+"&deg;)");
			
		}
		
		$("#target").append("<br>Total time observable: <b>"+observable.toFixed(2)+ "hrs</b>");
		
		$("#target").append("<br>Max target altitude: <b>"+str_pad(maxAltTime.getUTCHours())+":"+str_pad(maxAltTime.getUTCMinutes())+ "</b> ("+maxAlt.toFixed(1)+"&deg;)");
		$("#target").append("<br>Min moon distance: <b>"+minMoonDist.toFixed(1)+ "&deg; </b>");
		$("#target").append("<br>Mean moon phase: <b>"+meanMoonPhase.toFixed(1)+ "% </b>");
	}

